class RedisDistributedCache:
    def __init__(self, 
                 nodes: List[Dict[str, Any]] = None,
                 password: Optional[str] = None,
                 ssl: bool = True,
                 decode_responses: bool = True,
                 max_connections: int = 50):
        
        if nodes is None:
            nodes = [
                {"host": "redis-node-1.example.com", "port": 6379},
                {"host": "redis-node-2.example.com", "port": 6379},
                {"host": "redis-node-3.example.com", "port": 6379}
            ]
        
        startup_nodes = [ClusterNode(node["host"], node["port"]) for node in nodes]
        
        self.client = RedisCluster(
            startup_nodes=startup_nodes,
            password=password or os.getenv("REDIS_PASSWORD"),
            ssl=ssl,
            decode_responses=decode_responses,
            max_connections=max_connections,
            socket_connect_timeout=5,
            socket_keepalive=True,
            health_check_interval=30
        )
        
        self.default_ttl = 3600
        self.session_ttl = 1800
        self.api_key_ttl = 86400
    
    def _hash_key(self, key: str) -> str:
        return hashlib.sha256(key.encode()).hexdigest()
    
    def store_session_token(self, user_id: str, session_token: str, 
                           metadata: Optional[Dict] = None, 
                           ttl: Optional[int] = None) -> bool:
        key = f"session:{user_id}:{self._hash_key(session_token)}"
        
        session_data = {
            "token": session_token,
            "user_id": user_id,
            "created_at": int(time.time()),
            "metadata": metadata or {}
        }
        
        ttl_seconds = ttl or self.session_ttl
        
        try:
            self.client.setex(
                key,
                ttl_seconds,
                json.dumps(session_data)
            )
            
            user_sessions_key = f"user_sessions:{user_id}"
            self.client.sadd(user_sessions_key, key)
            self.client.expire(user_sessions_key, ttl_seconds)
            
            return True
        except Exception as e:
            print(f"Error storing session token: {e}")
            return False
    
    def get_session_token(self, user_id: str, session_token: str) -> Optional[Dict]:
        key = f"session:{user_id}:{self._hash_key(session_token)}"
        
        try:
            data = self.client.get(key)
            if data:
                return json.loads(data)
            return None
        except Exception as e:
            print(f"Error retrieving session token: {e}")
            return None
    
    def invalidate_session_token(self, user_id: str, session_token: str) -> bool:
        key = f"session:{user_id}:{self._hash_key(session_token)}"
        
        try:
            self.client.delete(key)
            
            user_sessions_key = f"user_sessions:{user_id}"
            self.client.srem(user_sessions_key, key)
            
            return True
        except Exception as e:
            print(f"Error invalidating session token: {e}")
            return False
    
    def invalidate_all_user_sessions(self, user_id: str) -> bool:
        user_sessions_key = f"user_sessions:{user_id}"
        
        try:
            session_keys = self.client.smembers(user_sessions_key)
            
            if session_keys:
                self.client.delete(*session_keys)
            
            self.client.delete(user_sessions_key)
            
            return True
        except Exception as e:
            print(f"Error invalidating all user sessions: {e}")
