        key = f"api_key:{self._hash_key(api_key)}"
        
        api_key_data = {
            "api_key": api_key,
            "user_id": user_id,
            "scopes": scopes or [],
            "created_at": int(time.time()),
            "metadata": metadata or {}
        }
        
        ttl_seconds = ttl or self.api_key_ttl
        
        try:
            self.client.setex(
                key,
                ttl_seconds,
                json.dumps(api_key_data)
            )
            
            user_api_keys_key = f"user_api_keys:{user_id}"
            self.client.sadd(user_api_keys_key, key)
            self.client.expire(user_api_keys_key, ttl_seconds)
            
            return True
        except Exception as e:
            print(f"Error storing API key: {e}")
