    def get_api_key(self, api_key: str) -> Optional[Dict]:
        key = f"api_key:{self._hash_key(api_key)}"
        
        try:
            data = self.client.get(key)
            if data:
                return json.loads(data)
            return None
        except Exception as e:
            print(f"Error retrieving API key: {e}")
            return None
    
    def validate_api_key(self, api_key: str, required_scopes: List[str] = None) -> bool:
        api_key_data = self.get_api_key(api_key)
        
        if not api_key_data:
            return False
        
        if required_scopes:
            key_scopes = set(api_key_data.get("scopes", []))
            required = set(required_scopes)
            if not required.issubset(key_scopes):
                return False
        
        return True
    
    def revoke_api_key(self, api_key: str) -> bool:
        key = f"api_key:{self._hash_key(api_key)}"
        
        try:
            api_key_data = self.get_api_key(api_key)
            if api_key_data:
                user_id = api_key_data.get("user_id")
                user_api_keys_key = f"user_api_keys:{user_id}"
                self.client.srem(user_api_keys_key, key)
            
            self.client.delete(key)
            return True
        except Exception as e:
            print(f"Error revoking API key: {e}")
