    def set_cached_data(self, key: str, value: Any, ttl: Optional[int] = None) -> bool:
        try:
            ttl_seconds = ttl or self.default_ttl
            
            if isinstance(value, (dict, list)):
                value = json.dumps(value)
            
            self.client.setex(
                f"cache:{key}",
                ttl_seconds,
                value
            )
            return True
        except Exception as e:
            print(f"Error setting cached data: {e}")
            return False
    
    def get_cached_data(self, key: str, parse_json: bool = True) -> Optional[Any]:
        try:
            data = self.client.get(f"cache:{key}")
            
            if data and parse_json:
                try:
                    return json.loads(data)
                except json.JSONDecodeError:
                    return data
            
            return data
        except Exception as e:
            print(f"Error getting cached data: {e}")
