class CacheService:
    def __init__(self):
        self.cache = RedisDistributedCache()
    
    def authenticate_session(self, user_id: str, session_token: str) -> bool:
        session_data = self.cache.get_session_token(user_id, session_token)
        return session_data is not None
    
    def authenticate_api_key(self, api_key: str, required_scopes: List[str] = None) -> bool:
        return self.cache.validate_api_key(api_key, required_scopes)
    
    def create_user_session(self, user_id: str, session_token: str, 
                          ip_address: str = None, user_agent: str = None) -> bool:
        metadata = {
            "ip_address": ip_address,
            "user_agent": user_agent
        }
        return self.cache.store_session_token(user_id, session_token, metadata)
    
    def logout_user(self, user_id: str, session_token: str) -> bool:
        return self.cache.invalidate_session_token(user_id, session_token)
    
    def logout_all_devices(self, user_id: str) -> bool:
        return self.cache.invalidate_all_user_sessions(user_id)
    
    def register_api_key(self, user_id: str, api_key: str, 
                        scopes: List[str], name: str = None) -> bool:
        metadata = {"name": name} if name else {}
        return self.cache.store_api_key(user_id, api_key, scopes, metadata)
    
    def check_rate_limit(self, user_id: str, endpoint: str, 
                        max_requests: int = 100, window: int = 60) -> Dict[str, Any]:
        identifier = f"{user_id}:{endpoint}"
        return self.cache.rate_limit_check(identifier, max_requests, window)


